import { useConfirm } from "@/components/ConfirmDialog";
import { Modal } from "@/components/Modal";
import { useToast } from "@/components/Toast";
import { exportArrayToExcel, exportToExcel } from "@/lib/excelExport";
import { isExactMatch, similarity } from "@/lib/similarity";
import { formatDate, formatMoney, genId } from "@/lib/utils-tr";
import type { Cari as CariType, DB } from "@/types";
import { useState } from "react";

interface Props {
  db: DB;
  save: (fn: (prev: DB) => DB) => void;
}

const empty: Omit<CariType, "id" | "createdAt" | "updatedAt"> = {
  name: "",
  type: "musteri",
  taxNo: "",
  phone: "",
  email: "",
  address: "",
  balance: 0,
  note: "",
};

// Bir carinin borcunun ka├º g├╝nd├╝r beklendi─ƒini hesapla
function calcDebtDays(
  cari: CariType,
  db: { sales: import("@/types").Sale[]; kasa: import("@/types").KasaEntry[] },
): number | null {
  if (cari.balance <= 0) return null;
  const lastPayment = db.kasa
    .filter((k) => !k.deleted && k.cariId === cari.id && k.type === "gelir")
    .sort(
      (a, b) =>
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
    )[0];
  const lastPaymentDate = lastPayment ? new Date(lastPayment.createdAt) : null;
  const unpaidSales = db.sales
    .filter(
      (s) =>
        !s.deleted &&
        s.status === "tamamlandi" &&
        (s.cariId === cari.id || s.customerId === cari.id),
    )
    .filter((s) => !lastPaymentDate || new Date(s.createdAt) > lastPaymentDate)
    .sort(
      (a, b) =>
        new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime(),
    );
  const oldestUnpaid = unpaidSales[0];
  if (oldestUnpaid)
    return Math.floor(
      (Date.now() - new Date(oldestUnpaid.createdAt).getTime()) / 86400000,
    );
  if (cari.lastTransaction)
    return Math.floor(
      (Date.now() - new Date(cari.lastTransaction).getTime()) / 86400000,
    );
  return null;
}

function debtColor(days: number | null): {
  color: string;
  bg: string;
  label: string;
} {
  if (days === null) return { color: "#64748b", bg: "transparent", label: "" };
  if (days <= 7)
    return { color: "#10b981", bg: "rgba(16,185,129,0.1)", label: `${days}g` };
  if (days <= 30)
    return { color: "#f59e0b", bg: "rgba(245,158,11,0.1)", label: `${days}g` };
  if (days <= 60)
    return {
      color: "#ef4444",
      bg: "rgba(239,68,68,0.12)",
      label: `${days}g ΓÜá∩╕Å`,
    };
  return { color: "#dc2626", bg: "rgba(220,38,38,0.18)", label: `${days}g ≡ƒö┤` };
}

export default function Cari({ db, save }: Props) {
  const { showToast } = useToast();
  const { showConfirm } = useConfirm();
  const [modalOpen, setModalOpen] = useState(false);
  const [filter, setFilter] = useState<"all" | "musteri" | "tedarikci">("all");
  const [search, setSearch] = useState("");
  const [sortBy, setSortBy] = useState<"name" | "balance" | "debt_days">(
    "name",
  );
  const [showOnlyDebt, setShowOnlyDebt] = useState(false);
  const [form, setForm] = useState<Partial<CariType>>(empty);
  const [editId, setEditId] = useState<string | null>(null);
  const [detailId, setDetailId] = useState<string | null>(null);
  const [islemModal, setIslemModal] = useState<{
    cariId: string;
    cariName: string;
    type: "musteri" | "tedarikci";
  } | null>(null);
  const [islemForm, setIslemForm] = useState({
    amount: "",
    kasa: "nakit",
    description: "",
  });

  let cari = db.cari.filter((c) => !c.deleted);
  if (filter !== "all") cari = cari.filter((c) => c.type === filter);
  if (showOnlyDebt) cari = cari.filter((c) => c.balance > 0);
  if (search)
    cari = cari.filter(
      (c) =>
        c.name.toLowerCase().includes(search.toLowerCase()) ||
        (c.phone || "").includes(search),
    );

  const cariWithDays = cari.map((c) => ({
    ...c,
    debtDays: calcDebtDays(c, db),
  }));
  const sorted = [...cariWithDays].sort((a, b) => {
    if (sortBy === "balance") return b.balance - a.balance;
    if (sortBy === "debt_days") return (b.debtDays ?? -1) - (a.debtDays ?? -1);
    return (a.name || "").localeCompare(b.name || "", "tr");
  });

  const aging = {
    "0-7": cariWithDays.filter(
      (c) => c.type === "musteri" && c.debtDays !== null && c.debtDays <= 7,
    ),
    "8-30": cariWithDays.filter(
      (c) =>
        c.type === "musteri" &&
        c.debtDays !== null &&
        c.debtDays > 7 &&
        c.debtDays <= 30,
    ),
    "31-60": cariWithDays.filter(
      (c) =>
        c.type === "musteri" &&
        c.debtDays !== null &&
        c.debtDays > 30 &&
        c.debtDays <= 60,
    ),
    "60+": cariWithDays.filter(
      (c) => c.type === "musteri" && c.debtDays !== null && c.debtDays > 60,
    ),
  };

  const totalReceivable = db.cari
    .filter((c) => !c.deleted && c.type === "musteri" && c.balance > 0)
    .reduce((s, c) => s + c.balance, 0);
  const totalPayable = db.cari
    .filter((c) => !c.deleted && c.type === "tedarikci" && c.balance > 0)
    .reduce((s, c) => s + c.balance, 0);

  const openAdd = () => {
    setForm({ ...empty });
    setEditId(null);
    setModalOpen(true);
  };
  const openEdit = (c: CariType) => {
    setForm({ ...c });
    setEditId(c.id);
    setModalOpen(true);
  };

  const handleSave = () => {
    const trimmedName = (form.name || "").trim();
    if (!trimmedName) {
      showToast("Ad gerekli!", "error");
      return;
    }
    const nowIso = new Date().toISOString();

    if (
      !editId ||
      !isExactMatch(
        trimmedName,
        db.cari.find((c) => c.id === editId)?.name || "",
      )
    ) {
      const aktifCari = db.cari.filter((c) => !c.deleted && c.id !== editId);
      const tamEslesme = aktifCari.find((c) =>
        isExactMatch(c.name, trimmedName),
      );
      if (tamEslesme) {
        showToast(
          `"${tamEslesme.name}" ad─▒nda cari zaten var! Kay─▒t engellendi.`,
          "error",
        );
        return;
      }
      const benzer = aktifCari.find(
        (c) => similarity(c.name, trimmedName) >= 70,
      );
      if (benzer) {
        const devamEt = window.confirm(
          `ΓÜá∩╕Å "${benzer.name}" ad─▒nda benzer bir cari mevcut.\nYine de kaydetmek istiyor musunuz?`,
        );
        if (!devamEt) return;
      }
    }

    save((prev) => {
      const cari = [...prev.cari];
      if (editId) {
        const i = cari.findIndex((c) => c.id === editId);
        if (i >= 0)
          cari[i] = {
            ...cari[i],
            ...form,
            name: trimmedName,
            updatedAt: nowIso,
          } as CariType;
        showToast("Cari g├╝ncellendi!", "success");
      } else {
        cari.push({
          id: genId(),
          createdAt: nowIso,
          updatedAt: nowIso,
          name: trimmedName,
          type: "musteri",
          balance: 0,
          ...form,
        } as CariType);
        showToast("Cari eklendi!", "success");
      }
      return { ...prev, cari };
    });
    setModalOpen(false);
  };

  const handleIslem = () => {
    if (!islemModal) return;
    const amount = parseFloat(islemForm.amount);
    if (!amount || amount <= 0) {
      showToast("Ge├ºerli tutar girin!", "error");
      return;
    }
    const nowIso = new Date().toISOString();
    const isTahsilat = islemModal.type === "musteri"; // m├╝┼ƒteriden tahsilat = gelir; tedarik├ºiye ├╢deme = gider
    const kasaType = isTahsilat ? ("gelir" as const) : ("gider" as const);
    const category = isTahsilat ? "tahsilat" : "tedarik";
    const desc =
      islemForm.description ||
      (isTahsilat
        ? `Tahsilat: ${islemModal.cariName}`
        : `├ûdeme: ${islemModal.cariName}`);

    save((prev) => {
      const kasaEntry = {
        id: genId(),
        type: kasaType,
        category,
        amount,
        kasa: islemForm.kasa,
        description: desc,
        cariId: islemModal.cariId,
        relatedId: islemModal.cariId,
        createdAt: nowIso,
        updatedAt: nowIso,
      };
      // Her iki durumda da cari bakiye azal─▒r (alacak tahsil edildi / bor├º ├╢dendi)
      const cari = prev.cari.map((c) =>
        c.id === islemModal.cariId
          ? {
              ...c,
              balance: (c.balance || 0) - amount,
              lastTransaction: nowIso,
              updatedAt: nowIso,
            }
          : c,
      );

      // Ortak cari ise ΓåÆ kasadan ├ºekim ortakEmanetler'e de yaz─▒l─▒r
      const cariRec = prev.cari.find((c) => c.id === islemModal.cariId);
      let ortakEmanetler = prev.ortakEmanetler || [];
      if (cariRec?.ortak && cariRec?.partnerId && kasaType === "gider") {
        ortakEmanetler = [
          ...ortakEmanetler,
          {
            id: genId(),
            partnerId: cariRec.partnerId,
            description: desc || `Kasadan ├ºekim: ${islemModal.cariName}`,
            amount,
            note: `Kasa: ${islemForm.kasa}`,
            type: "emanet" as const,
            createdAt: nowIso,
            updatedAt: nowIso,
          },
        ];
      }

      return { ...prev, kasa: [...prev.kasa, kasaEntry], cari, ortakEmanetler };
    });

    showToast(
      isTahsilat
        ? `Tahsilat kaydedildi: ${formatMoney(amount)}`
        : `├ûdeme kaydedildi: ${formatMoney(amount)}`,
      "success",
    );
    setIslemModal(null);
    setIslemForm({ amount: "", kasa: "nakit", description: "" });
  };

  const handleDelete = (id: string) => {
    // ─░li┼ƒkili kay─▒t kontrol├╝
    const relatedSales = db.sales.filter(
      (s) => !s.deleted && (s.customerId === id || s.cariId === id),
    );
    const relatedKasa = db.kasa.filter((k) => !k.deleted && k.cariId === id);
    const hasRelated = relatedSales.length > 0 || relatedKasa.length > 0;
    const msg = hasRelated
      ? `Bu cariye ait ${relatedSales.length} sat─▒┼ƒ ve ${relatedKasa.length} kasa kayd─▒ var. Silinen cari gizlenecek ancak ge├ºmi┼ƒ kay─▒tlar korunacak.`
      : "Bu cari kayd─▒n─▒ silmek istedi─ƒinizden emin misiniz?";
    showConfirm("Cari Sil", msg, () => {
      const nowIso = new Date().toISOString();
      save((prev) => ({
        ...prev,
        cari: prev.cari.map((c) =>
          c.id === id ? { ...c, deleted: true, updatedAt: nowIso } : c,
        ),
      }));
      showToast("Cari silindi!", "success");
    });
  };

  const detail = detailId ? db.cari.find((c) => c.id === detailId) : null;
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const detailDebtDays = detail ? calcDebtDays(detail, db) : null;
  const detailKasa = detailId
    ? db.kasa
        .filter((k) => !k.deleted && k.cariId === detailId)
        .sort(
          (a, b) =>
            new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
        )
        .slice(0, 30)
    : [];
  const detailSales =
    detailId && detail
      ? db.sales
          .filter(
            (s) =>
              s.cariId === detailId ||
              s.cariName === detail.name ||
              s.customerName === detail.name,
          )
          .sort(
            (a, b) =>
              new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
          )
          .slice(0, 20)
      : [];
  const detailInvoices = detailId
    ? (db.invoices || [])
        .filter(
          (inv) =>
            inv.cariId === detailId || (detail && inv.cariName === detail.name),
        )
        .sort(
          (a, b) =>
            new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
        )
        .slice(0, 20)
    : [];
  const totalPaid = detailKasa
    .filter((k) => k.type === "gelir")
    .reduce((s, k) => s + k.amount, 0);
  const totalPurchased =
    detailSales.reduce((s, s2) => s + s2.total, 0) +
    detailInvoices
      .filter((i) => i.type === "satis")
      .reduce((s, i) => s + i.total, 0);
  const [histTab, setHistTab] = useState<"kasa" | "satis" | "fatura">("kasa");

  return (
    <div>
      {/* Stat kartlar─▒ */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))",
          gap: 12,
          marginBottom: 16,
        }}
      >
        <StatCard
          label="Toplam Cari"
          value={String(db.cari.filter((c) => !c.deleted).length)}
          color="#3b82f6"
        />
        <StatCard
          label="Alacak"
          value={formatMoney(totalReceivable)}
          color="#10b981"
          sub="M├╝┼ƒterilerden"
        />
        <StatCard
          label="Bor├º"
          value={formatMoney(totalPayable)}
          color="#ef4444"
          sub="Tedarik├ºilere"
        />
      </div>

      {/* Alacak Ya┼ƒland─▒rma Band─▒ */}
      {(aging["8-30"].length > 0 ||
        aging["31-60"].length > 0 ||
        aging["60+"].length > 0) && (
        <div
          style={{
            background: "rgba(15,23,42,0.6)",
            border: "1px solid rgba(255,255,255,0.07)",
            borderRadius: 14,
            padding: "14px 18px",
            marginBottom: 16,
          }}
        >
          <div
            style={{
              color: "#94a3b8",
              fontSize: "0.72rem",
              fontWeight: 700,
              textTransform: "uppercase",
              letterSpacing: "0.07em",
              marginBottom: 12,
            }}
          >
            ΓÅ▒∩╕Å Alacak Ya┼ƒland─▒rma
          </div>
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
            {[
              {
                label: "0ΓÇô7 g├╝n",
                items: aging["0-7"],
                color: "#10b981",
                bg: "rgba(16,185,129,0.1)",
              },
              {
                label: "8ΓÇô30 g├╝n",
                items: aging["8-30"],
                color: "#f59e0b",
                bg: "rgba(245,158,11,0.1)",
              },
              {
                label: "31ΓÇô60 g├╝n",
                items: aging["31-60"],
                color: "#ef4444",
                bg: "rgba(239,68,68,0.12)",
              },
              {
                label: "60+ g├╝n",
                items: aging["60+"],
                color: "#dc2626",
                bg: "rgba(220,38,38,0.18)",
              },
            ].map((bucket) => (
              <div
                key={bucket.label}
                onClick={() => {
                  setFilter("musteri");
                  setShowOnlyDebt(true);
                  setSortBy("debt_days");
                }}
                style={{
                  flex: "1 1 120px",
                  background: bucket.bg,
                  border: `1px solid ${bucket.color}30`,
                  borderRadius: 10,
                  padding: "10px 14px",
                  cursor: "pointer",
                  transition: "all 0.2s",
                }}
              >
                <div
                  style={{
                    color: bucket.color,
                    fontSize: "1.2rem",
                    fontWeight: 900,
                    lineHeight: 1,
                  }}
                >
                  {bucket.items.length}
                  <span
                    style={{
                      fontSize: "0.72rem",
                      fontWeight: 600,
                      marginLeft: 4,
                    }}
                  >
                    m├╝┼ƒteri
                  </span>
                </div>
                <div
                  style={{
                    color: bucket.color,
                    fontSize: "0.75rem",
                    fontWeight: 700,
                    marginTop: 3,
                  }}
                >
                  {formatMoney(bucket.items.reduce((s, c) => s + c.balance, 0))}
                </div>
                <div
                  style={{
                    color: "#475569",
                    fontSize: "0.65rem",
                    marginTop: 2,
                  }}
                >
                  {bucket.label}
                </div>
              </div>
            ))}
          </div>
          {aging["60+"].length > 0 && (
            <div
              style={{
                marginTop: 12,
                display: "flex",
                flexDirection: "column",
                gap: 6,
              }}
            >
              <div
                style={{
                  color: "#dc2626",
                  fontSize: "0.72rem",
                  fontWeight: 700,
                }}
              >
                ≡ƒö┤ 60+ g├╝n bekleyen alacaklar:
              </div>
              {aging["60+"].slice(0, 5).map((c) => (
                <div
                  key={c.id}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 10,
                    background: "rgba(220,38,38,0.08)",
                    borderRadius: 8,
                    padding: "7px 12px",
                  }}
                >
                  <span
                    style={{
                      color: "#f1f5f9",
                      fontWeight: 600,
                      fontSize: "0.85rem",
                      flex: 1,
                    }}
                  >
                    {c.name}
                  </span>
                  {c.phone && (
                    <span style={{ color: "#64748b", fontSize: "0.78rem" }}>
                      ≡ƒô₧ {c.phone}
                    </span>
                  )}
                  <span
                    style={{
                      color: "#ef4444",
                      fontWeight: 700,
                      fontSize: "0.85rem",
                    }}
                  >
                    {formatMoney(c.balance)}
                  </span>
                  <span
                    style={{
                      color: "#dc2626",
                      fontSize: "0.72rem",
                      fontWeight: 700,
                      background: "rgba(220,38,38,0.2)",
                      borderRadius: 5,
                      padding: "2px 7px",
                    }}
                  >
                    {c.debtDays}g
                  </span>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      setIslemModal({
                        cariId: c.id,
                        cariName: c.name,
                        type: "musteri",
                      });
                      setIslemForm({
                        amount: String(c.balance),
                        kasa: "nakit",
                        description: "",
                      });
                    }}
                    style={{
                      background: "rgba(16,185,129,0.15)",
                      border: "none",
                      borderRadius: 6,
                      color: "#10b981",
                      padding: "4px 10px",
                      cursor: "pointer",
                      fontSize: "0.75rem",
                      fontWeight: 700,
                      whiteSpace: "nowrap",
                    }}
                  >
                    ≡ƒÆ░ Tahsil Et
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      <div
        style={{
          display: "flex",
          gap: 10,
          marginBottom: 16,
          flexWrap: "wrap",
          alignItems: "center",
        }}
      >
        <button
          onClick={openAdd}
          style={{
            background: "#ff5722",
            border: "none",
            borderRadius: 10,
            color: "#fff",
            padding: "10px 20px",
            fontWeight: 700,
            cursor: "pointer",
          }}
        >
          + Yeni Cari
        </button>
        <button
          onClick={() => {
            exportToExcel(db, { sheets: ["cari"] });
            showToast("Excel indirildi!", "success");
          }}
          style={{
            background: "rgba(139,92,246,0.15)",
            border: "1px solid rgba(139,92,246,0.3)",
            borderRadius: 10,
            color: "#a78bfa",
            padding: "10px 16px",
            fontWeight: 700,
            cursor: "pointer",
            fontSize: "0.85rem",
          }}
        >
          ≡ƒôè Excel ─░ndir
        </button>
        <button
          onClick={() => {
            const rows = sorted.map((c) => ({
              Ad: c.name,
              T├╝r: c.type === "musteri" ? "M├╝┼ƒteri" : "Tedarik├ºi",
              Bakiye: c.balance,
              "Bor├º G├╝n": c.debtDays ?? "",
              Telefon: c.phone || "",
              "E-posta": c.email || "",
              "Vergi No": c.taxNo || "",
              Adres: c.address || "",
               
              Not: (c as any).note || "",
            }));
            exportArrayToExcel(rows, "cari-listesi");
            showToast("Ekstre indirildi!", "success");
          }}
          style={{
            background: "rgba(16,185,129,0.12)",
            border: "1px solid rgba(16,185,129,0.25)",
            borderRadius: 10,
            color: "#10b981",
            padding: "10px 16px",
            fontWeight: 700,
            cursor: "pointer",
            fontSize: "0.85rem",
          }}
        >
          ≡ƒôÑ Ekstre
        </button>
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="≡ƒöì Ara..."
          style={{
            flex: 1,
            padding: "9px 13px",
            background: "#1e293b",
            border: "1px solid #334155",
            borderRadius: 10,
            color: "#f1f5f9",
          }}
        />
        {(["all", "musteri", "tedarikci"] as const).map((f) => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{
              padding: "8px 14px",
              border: "none",
              borderRadius: 8,
              cursor: "pointer",
              fontWeight: 600,
              fontSize: "0.82rem",
              background: filter === f ? "#ff5722" : "#273548",
              color: filter === f ? "#fff" : "#94a3b8",
            }}
          >
            {f === "all"
              ? "T├╝m├╝"
              : f === "musteri"
                ? "≡ƒæñ M├╝┼ƒteri"
                : "≡ƒÅ¡ Tedarik├ºi"}
          </button>
        ))}
        <button
          onClick={() => setShowOnlyDebt((v) => !v)}
          style={{
            padding: "8px 14px",
            border: "none",
            borderRadius: 8,
            cursor: "pointer",
            fontWeight: 600,
            fontSize: "0.82rem",
            background: showOnlyDebt ? "#ef4444" : "#273548",
            color: showOnlyDebt ? "#fff" : "#94a3b8",
          }}
        >
          {showOnlyDebt ? "≡ƒö┤ Bor├ºlular" : "Bor├ºlular"}
        </button>
        <select
          value={sortBy}
          onChange={(e) => setSortBy(e.target.value as typeof sortBy)}
          style={{
            padding: "8px 12px",
            background: "#1e293b",
            border: "1px solid #334155",
            borderRadius: 8,
            color: "#94a3b8",
