                >
                  <thead>
                    <tr>
                      {["No", "T├╝r", "Tarih", "Tutar", "Durum"].map((h) => (
                        <th
                          key={h}
                          style={{
                            padding: "8px 10px",
                            textAlign: "left",
                            color: "#334155",
                            fontSize: "0.7rem",
                            fontWeight: 700,
