                        </td>
                        <td style={{ padding: "8px 10px", color: "#64748b" }}>
                          {formatDate(inv.createdAt)}
                        </td>
                        <td
                          style={{
                            padding: "8px 10px",
                            color: "#10b981",
                            fontWeight: 700,
                          }}
                        >
                          {formatMoney(inv.total)}
                        </td>
                        <td style={{ padding: "8px 10px" }}>
                          <span
                            style={{
                              background:
                                inv.status === "odendi"
                                  ? "rgba(16,185,129,0.12)"
                                  : inv.status === "onaylandi"
                                    ? "rgba(59,130,246,0.12)"
                                    : "rgba(245,158,11,0.12)",
                              color:
                                inv.status === "odendi"
                                  ? "#10b981"
                                  : inv.status === "onaylandi"
                                    ? "#60a5fa"
                                    : "#f59e0b",
                              borderRadius: 5,
                              padding: "2px 7px",
                              fontSize: "0.72rem",
                              fontWeight: 700,
                            }}
                          >
                            {inv.status}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ))}
        </Modal>
      )}
    </div>
  );
}

