          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
            <div>
              <label style={lbl}>{form.type === 'satis' ? 'M├╝┼ƒteri' : 'Tedarik├ºi'} *</label>
