            </div>
            <div style={{ background: 'rgba(0,0,0,0.2)', borderRadius: 10, overflow: 'hidden' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr style={{ background: 'rgba(0,0,0,0.2)' }}>
                    {['A├º─▒klama', 'Adet', 'Birim Γé║', 'KDV %', 'Toplam', ''].map(h => (
                      <th key={h} style={{ padding: '8px 10px', textAlign: 'left', color: '#334155', fontSize: '0.7rem', fontWeight: 700 }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {form.items.map((it, idx) => (
                    <tr key={idx} style={{ borderTop: '1px solid rgba(255,255,255,0.04)' }}>
                      <td style={{ padding: '6px 8px' }}><input value={it.description} onChange={e => updateItem(idx, 'description', e.target.value)} style={{ ...inp, padding: '7px 10px', fontSize: '0.85rem' }} placeholder="├£r├╝n/Hizmet" /></td>
                      <td style={{ padding: '6px 8px', width: 70 }}><input type="number" inputMode="decimal" value={it.quantity} min={1} onChange={e => updateItem(idx, 'quantity', parseInt(e.target.value) || 1)} style={{ ...inp, padding: '7px 8px', fontSize: '0.85rem', width: 60 }} /></td>
                      <td style={{ padding: '6px 8px', width: 100 }}><input type="number" inputMode="decimal" value={it.unitPrice} min={0} onChange={e => updateItem(idx, 'unitPrice', parseFloat(e.target.value) || 0)} style={{ ...inp, padding: '7px 8px', fontSize: '0.85rem', width: 90 }} /></td>
                      <td style={{ padding: '6px 8px', width: 70 }}>
                        <select value={it.vatRate} onChange={e => updateItem(idx, 'vatRate', parseInt(e.target.value))} style={{ ...inp, padding: '7px 6px', fontSize: '0.85rem', width: 60 }}>
                          <option value={0}>0</option><option value={1}>1</option><option value={10}>10</option><option value={20}>20</option>
                        </select>
                      </td>
                      <td style={{ padding: '6px 8px', color: '#10b981', fontWeight: 700, fontSize: '0.85rem', whiteSpace: 'nowrap' }}>{formatMoney(it.quantity * it.unitPrice * (1 + it.vatRate / 100))}</td>
                      <td style={{ padding: '6px 8px', width: 30 }}>
                        {form.items.length > 1 && <button onClick={() => removeItem(idx)} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '0.85rem' }}>├ù</button>}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Totals + Details */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
            <div>
              <div style={{ display: 'grid', gap: 10 }}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
                  <div>
                    <label style={lbl}>├ûdeme</label>
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    <select value={form.payment} onChange={e => setForm(f => ({ ...f, payment: e.target.value as any }))} style={inp}>
                      {Object.entries(paymentLabels).map(([k, v]) => <option key={k} value={k}>{v}</option>)}
                    </select>
                  </div>
                  <div><label style={lbl}>Vade Tarihi</label><input type="date" value={form.dueDate} onChange={e => setForm(f => ({ ...f, dueDate: e.target.value }))} style={inp} /></div>
                </div>
                <div>
                  <label style={lbl}>Durum</label>
                  // eslint-disable-next-line @typescript-eslint/no-explicit-any
                  <select value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value as any }))} style={inp}>
                    <option value="taslak">≡ƒô¥ Taslak</option><option value="onaylandi">Γ£à Onayland─▒</option><option value="odendi">≡ƒÆ░ ├ûdendi</option><option value="iptal">Γ¥î ─░ptal</option>
                  </select>
                </div>
                <div><label style={lbl}>Not</label><textarea value={form.note} onChange={e => setForm(f => ({ ...f, note: e.target.value }))} style={{ ...inp, minHeight: 50 }} /></div>
                <div>
                  <label style={lbl}>─░lgili Sat─▒┼ƒ (opsiyonel)</label>
                  <select value={form.saleId} onChange={e => setForm(f => ({ ...f, saleId: e.target.value }))} style={inp}>
                    <option value="">-- Sat─▒┼ƒ Se├º --</option>
                    {(db.sales || []).filter(s => !s.deleted).map(s => (
                      <option key={s.id} value={s.id}>{formatDate(s.createdAt)} ΓÇö {s.productName} ({formatMoney(s.total)})</option>
                    ))}
                  </select>
                </div>
              </div>
            </div>
            <div style={{ background: 'rgba(0,0,0,0.3)', borderRadius: 12, padding: '14px 16px' }}>
              <TotalRow label="Ara Toplam" value={formatMoney(formTotals.subtotal)} />
              <TotalRow label="KDV Toplam" value={formatMoney(formTotals.vatTotal)} color="#3b82f6" />
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
                <span style={{ color: '#64748b', fontSize: '0.82rem', flex: 1 }}>─░skonto</span>
                <input type="number" inputMode="decimal" value={form.discount} min={0} onChange={e => setForm(f => ({ ...f, discount: parseFloat(e.target.value) || 0 }))} style={{ ...inp, width: 100, padding: '5px 8px', fontSize: '0.85rem', textAlign: 'right' }} />
              </div>
              <div style={{ borderTop: '1px solid rgba(255,255,255,0.08)', paddingTop: 10, marginTop: 4 }}>
                <TotalRow label="GENEL TOPLAM" value={formatMoney(formTotals.total)} color="#10b981" big />
              </div>
            </div>
          </div>

          <button onClick={handleSave} style={{ background: 'linear-gradient(135deg, #ff5722, #ff7043)', border: 'none', borderRadius: 12, color: '#fff', padding: '13px 0', fontWeight: 800, cursor: 'pointer', fontSize: '1rem' }}>
            ≡ƒÆ╛ {editId ? 'G├╝ncelle' : 'Fatura Olu┼ƒtur'}
          </button>
        </div>
      </Modal>

      {/* Preview Modal */}
      {previewInv && (
        <Modal open={true} onClose={() => setPreviewId(null)} title={`≡ƒôä Fatura: ${previewInv.invoiceNo}`} maxWidth={640}>
          <div style={{ background: 'rgba(0,0,0,0.2)', borderRadius: 12, padding: 20 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 18, paddingBottom: 14, borderBottom: '1px solid rgba(255,255,255,0.06)' }}>
              <div>
                <h3 style={{ color: '#f1f5f9', fontWeight: 800, fontSize: '1rem', marginBottom: 4 }}>{db.company.name || '┼₧irketiniz'}</h3>
                {db.company.taxNo && <p style={{ color: '#475569', fontSize: '0.82rem' }}>VKN: {db.company.taxNo}</p>}
                {db.company.phone && <p style={{ color: '#475569', fontSize: '0.82rem' }}>≡ƒô₧ {db.company.phone}</p>}
              </div>
              <div style={{ textAlign: 'right' }}>
                <p style={{ fontFamily: 'monospace', color: '#ff7043', fontWeight: 800, fontSize: '1rem' }}>{previewInv.invoiceNo}</p>
                <p style={{ color: '#475569', fontSize: '0.82rem' }}>{formatDate(previewInv.createdAt)}</p>
                <span style={{ background: `${statusColors[previewInv.status]}18`, color: statusColors[previewInv.status], borderRadius: 6, padding: '2px 8px', fontSize: '0.78rem', fontWeight: 700 }}>{statusLabels[previewInv.status]}</span>
              </div>
            </div>
            <div style={{ marginBottom: 16 }}>
              <p style={{ color: '#334155', fontSize: '0.72rem', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 4 }}>{previewInv.type === 'satis' ? 'M├£┼₧TER─░' : 'TEDAR─░K├ç─░'}</p>
              <p style={{ color: '#f1f5f9', fontWeight: 700 }}>{previewInv.cariName}</p>
              {previewInv.cariTaxNo && <p style={{ color: '#475569', fontSize: '0.82rem' }}>VKN: {previewInv.cariTaxNo}</p>}
              {previewInv.cariAddress && <p style={{ color: '#475569', fontSize: '0.82rem' }}>{previewInv.cariAddress}</p>}
            </div>
            <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: 14 }}>
              <thead>
                <tr style={{ borderBottom: '1px solid rgba(255,255,255,0.08)' }}>
                  {['A├º─▒klama', 'Adet', 'Birim', 'KDV', 'Toplam'].map(h => <th key={h} style={{ padding: '8px 10px', textAlign: 'left', color: '#334155', fontSize: '0.72rem', fontWeight: 700 }}>{h}</th>)}
                </tr>
              </thead>
              <tbody>
                {previewInv.items.map((it, i) => (
                  <tr key={i} style={{ borderBottom: '1px solid rgba(255,255,255,0.04)' }}>
                    <td style={{ padding: '8px 10px', color: '#e2e8f0', fontSize: '0.88rem' }}>{it.description}</td>
                    <td style={{ padding: '8px 10px', color: '#94a3b8', fontSize: '0.85rem' }}>{it.quantity}</td>
                    <td style={{ padding: '8px 10px', color: '#94a3b8', fontSize: '0.85rem' }}>{formatMoney(it.unitPrice)}</td>
                    <td style={{ padding: '8px 10px', color: '#94a3b8', fontSize: '0.85rem' }}>%{it.vatRate}</td>
                    <td style={{ padding: '8px 10px', color: '#10b981', fontWeight: 700, fontSize: '0.88rem' }}>{formatMoney(it.total)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
            <div style={{ borderTop: '1px solid rgba(255,255,255,0.06)', paddingTop: 12 }}>
              <TotalRow label="Ara Toplam" value={formatMoney(previewInv.subtotal)} />
              <TotalRow label="KDV" value={formatMoney(previewInv.vatTotal)} color="#3b82f6" />
              {previewInv.discount > 0 && <TotalRow label="─░skonto" value={`-${formatMoney(previewInv.discount)}`} color="#ef4444" />}
              <div style={{ borderTop: '1px solid rgba(255,255,255,0.08)', paddingTop: 8, marginTop: 6 }}>
                <TotalRow label="GENEL TOPLAM" value={formatMoney(previewInv.total)} color="#10b981" big />
              </div>
            </div>
            {previewInv.note && <p style={{ color: '#475569', fontSize: '0.82rem', marginTop: 12, fontStyle: 'italic' }}>Not: {previewInv.note}</p>}
          </div>

          {/* Taksit Plan─▒ B├╢l├╝m├╝ */}
          {(() => {
            const installments = (db.installments || []).filter(i => i.invoiceId === previewInv.id);
            const today = new Date(); today.setHours(0, 0, 0, 0);
            return (
              <div style={{ marginTop: 16, background: 'rgba(0,0,0,0.15)', borderRadius: 12, padding: 16 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
                  <span style={{ color: '#94a3b8', fontWeight: 700, fontSize: '0.88rem' }}>≡ƒôà Taksit Plan─▒</span>
                  {installments.length === 0 && (
                    <button onClick={() => setShowInstForm(v => !v)} style={{ background: 'rgba(139,92,246,0.15)', border: '1px solid rgba(139,92,246,0.3)', borderRadius: 8, color: '#a78bfa', padding: '5px 12px', cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem' }}>
                      ≡ƒôà Taksit Plan─▒ Olu┼ƒtur
                    </button>
                  )}
                </div>

                {showInstForm && installments.length === 0 && (
                  <div style={{ background: 'rgba(0,0,0,0.2)', borderRadius: 10, padding: 12, marginBottom: 12, display: 'grid', gap: 10 }}>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
                      <div>
                        <label style={lbl}>Taksit Say─▒s─▒ (2-24)</label>
                        <input type="number" min={2} max={24} value={instForm.count}
                          onChange={e => setInstForm(f => ({ ...f, count: Math.min(24, Math.max(2, parseInt(e.target.value) || 2)) }))}
                          style={inp} />
                      </div>
                      <div>
                        <label style={lbl}>─░lk Vade Tarihi</label>
                        <input type="date" value={instForm.firstDueDate}
                          onChange={e => setInstForm(f => ({ ...f, firstDueDate: e.target.value }))}
                          style={inp} />
                      </div>
                    </div>
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button onClick={() => createInstallments(previewInv.id, previewInv.total)}
                        style={{ flex: 1, background: 'linear-gradient(135deg, #8b5cf6, #7c3aed)', border: 'none', borderRadius: 8, color: '#fff', padding: '9px 0', cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem' }}>
                        Γ£ô Olu┼ƒtur
                      </button>
                      <button onClick={() => setShowInstForm(false)}
                        style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 8, color: '#64748b', padding: '9px 14px', cursor: 'pointer', fontSize: '0.85rem' }}>
                        ─░ptal
                      </button>
                    </div>
                  </div>
                )}

                {installments.length > 0 ? (
                  <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                    <thead>
                      <tr style={{ background: 'rgba(0,0,0,0.2)' }}>
                        {['#', 'Vade', 'Tutar', 'Durum', ''].map(h => (
                          <th key={h} style={{ padding: '7px 10px', textAlign: 'left', color: '#334155', fontSize: '0.7rem', fontWeight: 700 }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {installments.map((inst, idx) => {
                        const due = new Date(inst.dueDate); due.setHours(0, 0, 0, 0);
                        const isOverdue = !inst.paid && due < today;
                        const isToday = !inst.paid && due.getTime() === today.getTime();
                        const rowBg = inst.paid ? 'rgba(16,185,129,0.08)' : isOverdue ? 'rgba(239,68,68,0.1)' : isToday ? 'rgba(245,158,11,0.1)' : 'rgba(255,255,255,0.02)';
                        const statusColor = inst.paid ? '#10b981' : isOverdue ? '#ef4444' : isToday ? '#f59e0b' : '#64748b';
                        const statusLabel = inst.paid ? 'Γ£à ├ûdendi' : isOverdue ? 'ΓÜá∩╕Å Gecikmi┼ƒ' : isToday ? '≡ƒöö Bug├╝n' : 'ΓÅ│ Bekliyor';
                        return (
                          <tr key={inst.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.04)', background: rowBg }}>
                            <td style={{ padding: '8px 10px', color: '#64748b', fontSize: '0.82rem' }}>{idx + 1}</td>
                            <td style={{ padding: '8px 10px', color: '#e2e8f0', fontSize: '0.82rem' }}>{formatDate(inst.dueDate)}</td>
                            <td style={{ padding: '8px 10px', color: '#10b981', fontWeight: 700, fontSize: '0.85rem' }}>{formatMoney(inst.amount)}</td>
                            <td style={{ padding: '8px 10px' }}>
                              <span style={{ color: statusColor, fontSize: '0.78rem', fontWeight: 700 }}>{statusLabel}</span>
                            </td>
                            <td style={{ padding: '8px 10px' }}>
                              {!inst.paid && (
                                <button onClick={() => payInstallment(inst.id)}
                                  style={{ background: 'rgba(16,185,129,0.15)', border: '1px solid rgba(16,185,129,0.3)', borderRadius: 6, color: '#10b981', padding: '3px 10px', cursor: 'pointer', fontWeight: 700, fontSize: '0.75rem' }}>
                                  Γ£ô ├ûdendi
                                </button>
                              )}
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                ) : (
                  !showInstForm && <p style={{ color: '#334155', fontSize: '0.82rem', textAlign: 'center', padding: '10px 0' }}>Hen├╝z taksit plan─▒ yok</p>
                )}
              </div>
            );
          })()}

          <button onClick={() => { window.print(); }} style={{ width: '100%', marginTop: 14, padding: '11px 0', background: 'rgba(59,130,246,0.12)', border: '1px solid rgba(59,130,246,0.25)', borderRadius: 10, color: '#60a5fa', cursor: 'pointer', fontWeight: 700, fontSize: '0.9rem' }}>≡ƒû¿∩╕Å Yazd─▒r</button>
        </Modal>
      )}
    </div>
  );
}

const miniBtn: React.CSSProperties = { background: 'rgba(255,255,255,0.04)', border: 'none', borderRadius: 6, color: '#64748b', padding: '4px 6px', cursor: 'pointer', fontSize: '0.82rem' };
const lbl: React.CSSProperties = { display: 'block', marginBottom: 5, color: '#64748b', fontSize: '0.82rem', fontWeight: 600 };
const inp: React.CSSProperties = { width: '100%', padding: '9px 12px', background: 'rgba(0,0,0,0.4)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 8, color: '#f1f5f9', fontSize: '0.88rem', boxSizing: 'border-box' };

function TotalRow({ label, value, color, big }: { label: string; value: string; color?: string; big?: boolean }) {
  return (
    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
      <span style={{ color: big ? '#94a3b8' : '#475569', fontSize: big ? '0.95rem' : '0.82rem', fontWeight: big ? 700 : 400 }}>{label}</span>
      <span style={{ color: color || '#f1f5f9', fontWeight: big ? 900 : 600, fontSize: big ? '1.15rem' : '0.88rem' }}>{value}</span>
    </div>
  );
}

import { useMemo, useState, useEffect, useCallback } from 'react';
import { formatMoney } from '@/lib/utils-tr';
import { quickHealthCheck, runHealthCheck, type HealthReport, type HealthStatus } from '@/lib/healthCheck';
import type { DB } from '@/types';

interface Props { db: DB }
type Status = 'ok' | 'warn' | 'err';

const S: Record<Status, { bg: string; border: string; text: string; dot: string }> = {
  ok:   { bg: '#0d2e1a', border: '#22c55e', text: '#4ade80', dot: '#22c55e' },
  warn: { bg: '#2e2500', border: '#f59e0b', text: '#fbbf24', dot: '#f59e0b' },
  err:  { bg: '#2e0d0d', border: '#ef4444', text: '#f87171', dot: '#ef4444' },
};

// Halka konumlar─▒ ΓÇö 13 node, ├ºember ├╝zerinde e┼ƒit aral─▒kl─▒ (780├ù780 tuval)
const CX = 390; const CY = 390; const R = 310;
const NODE_IDS = [
  'tedarikci', 'disborc', 'kasa', 'pos_ziraat', 'pos_is', 'pos_yk',
  'tahsilat', 'otahsilat', 'satis', 'stok', 'malgiris', 'siparis', 'ocek',
] as const;
type NodeId = typeof NODE_IDS[number];

const NODE_LABELS: Record<NodeId, string> = {
  tedarikci:  'TEDAR─░K├ç─░',
  disborc:    'ORTAK DI┼₧ BOR├ç',
  kasa:       'KASA / BANKA',
  pos_ziraat: 'POS Z─░RAAT',
  pos_is:     'POS ─░┼₧',
  pos_yk:     'POS YAPIKREDI',
  tahsilat:   'TAHS─░LAT',
  otahsilat:  'ORTAK TAHS─░LAT',
  satis:      'SATI┼₧',
  stok:       'STOK',
  malgiris:   'MAL G─░R─░┼₧─░',
  siparis:    'S─░PAR─░┼₧',
  ocek:       'ORTAK ├çEK─░M',
};

const NODES: { id: NodeId; label: string; x: number; y: number }[] = NODE_IDS.map((id, i) => {
  const angle = (i / NODE_IDS.length) * 2 * Math.PI - Math.PI / 2;
  return { id, label: NODE_LABELS[id], x: Math.round(CX + R * Math.cos(angle)) - 75, y: Math.round(CY + R * Math.sin(angle)) - 35 };
});

const CONNECTIONS: [NodeId, NodeId][] = [
  ['tedarikci',  'siparis'],
  ['siparis',    'malgiris'],
  ['malgiris',   'stok'],
  ['stok',       'satis'],
  ['satis',      'tahsilat'],
  ['tahsilat',   'kasa'],
  ['kasa',       'pos_ziraat'],
  ['kasa',       'pos_is'],
  ['kasa',       'pos_yk'],
  ['disborc',    'kasa'],
  ['otahsilat',  'kasa'],
  ['ocek',       'kasa'],
  ['tedarikci',  'disborc'],
];

function kasaBal(kasa: DB['kasa'], kasaId: string): number {
  return kasa.filter(k => !k.deleted && k.kasa === kasaId)
    .reduce((s, k) => s + (k.type === 'gelir' ? k.amount : -k.amount), 0);
}

const STATUS_COLORS: Record<HealthStatus, { bg: string; border: string; text: string; label: string }> = {
  healthy:  { bg: 'rgba(34,197,94,0.08)',  border: 'rgba(34,197,94,0.3)',  text: '#22c55e', label: 'Sa─ƒl─▒kl─▒' },
  degraded: { bg: 'rgba(245,158,11,0.08)', border: 'rgba(245,158,11,0.3)', text: '#f59e0b', label: 'D├╝┼ƒ├╝k' },
  critical: { bg: 'rgba(239,68,68,0.08)',  border: 'rgba(239,68,68,0.3)',  text: '#ef4444', label: 'Kritik' },
};

export default function KontrolHalkasi({ db }: Props) {
  const [healthReport, setHealthReport] = useState<HealthReport | null>(() => {
    const quick = quickHealthCheck(db as any as Record<string, any>);
    return { ...quick, duration: 0 };
  });
  const [fullChecking, setFullChecking] = useState(false);

  // Sayfa a├º─▒l─▒nca tam sa─ƒl─▒k kontrol├╝ yap (Firebase dahil)
  useEffect(() => {
    setFullChecking(true);
    runHealthCheck(db as any as Record<string, any>).then(r => {
      setHealthReport(r);
      setFullChecking(false);
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const recheck = useCallback(() => {
    setFullChecking(true);
    runHealthCheck(db as any as Record<string, any>).then(r => {
      setHealthReport(r);
      setFullChecking(false);
    });
  }, [db]);

  const m = useMemo(() => {
    const nakit     = kasaBal(db.kasa, 'nakit');
    const banka     = kasaBal(db.kasa, 'banka');
    const posZ      = kasaBal(db.kasa, 'pos_ziraat');
    const posI      = kasaBal(db.kasa, 'pos_is');
    const posY      = kasaBal(db.kasa, 'pos_yk');
    const totalKasa = nakit + banka + posZ + posI + posY;

    const outOfStock = db.products.filter(p => !p.deleted && p.stock === 0).length;
    const lowStock   = db.products.filter(p => !p.deleted && p.stock > 0 && p.stock <= p.minStock).length;
    const totalStock = db.products.filter(p => !p.deleted).reduce((s, p) => s + p.stock, 0);

    const today = new Date().toDateString();
    const todaySales = db.sales.filter(s => !s.deleted && s.status === 'tamamlandi' && new Date(s.createdAt).toDateString() === today);

    const pendingOrders   = db.orders.filter(o => o.status === 'bekliyor').length;
    const inTransit       = db.orders.filter(o => o.status === 'yolda').length;
    const completedToday  = db.orders.filter(o => o.status === 'tamamlandi' && new Date(o.updatedAt).toDateString() === today).length;

    const totalReceivable = db.cari.filter(c => !c.deleted && c.type === 'musteri' && c.balance > 0).reduce((s, c) => s + c.balance, 0);
    const totalPayable    = db.cari.filter(c => !c.deleted && c.type === 'tedarikci' && c.balance > 0).reduce((s, c) => s + c.balance, 0);

    const ortakCekim    = (db.ortakEmanetler || []).filter(e => e.type === 'emanet').reduce((s, e) => s + e.amount, 0);
    const ortakTahsilat = (db.ortakEmanetler || []).filter(e => e.type === 'iade').reduce((s, e) => s + e.amount, 0);

    return {
      nakit, banka, posZ, posI, posY, totalKasa,
      outOfStock, lowStock, totalStock,
      todayCount: todaySales.length,
      todayAmount: todaySales.reduce((s, x) => s + x.total, 0),
      pendingOrders, inTransit, completedToday,
      totalReceivable, totalPayable,
      ortakCekim, ortakTahsilat,
      netSermaye: totalKasa + totalReceivable - totalPayable,
    };
  }, [db]);

  function getStatus(id: NodeId): Status {
    switch (id) {
      case 'stok':       return m.outOfStock > 0 ? 'err' : m.lowStock > 0 ? 'warn' : 'ok';
      case 'satis':      return m.todayCount === 0 ? 'warn' : 'ok';
      case 'siparis':    return m.pendingOrders > 0 ? 'warn' : 'ok';
      case 'malgiris':   return m.inTransit > 0 ? 'warn' : 'ok';
      case 'kasa':       return m.totalKasa <= 0 ? 'err' : m.totalKasa < 5000 ? 'warn' : 'ok';
      case 'pos_ziraat': return m.posZ === 0 ? 'warn' : 'ok';
      case 'pos_is':     return m.posI === 0 ? 'warn' : 'ok';
      case 'pos_yk':     return m.posY === 0 ? 'warn' : 'ok';
      case 'ocek':       return m.ortakCekim > 0 ? 'warn' : 'ok';
      case 'disborc':    return m.totalPayable > 100000 ? 'err' : m.totalPayable > 0 ? 'warn' : 'ok';
      case 'otahsilat':  return m.ortakTahsilat > 0 ? 'warn' : 'ok';
      case 'tahsilat':   return m.todayCount > 0 && m.totalKasa <= 0 ? 'warn' : 'ok';
      case 'tedarikci':  return m.totalPayable > 100000 ? 'err' : m.totalPayable > 0 ? 'warn' : 'ok';
    }
  }

  function getSub(id: NodeId): string {
    switch (id) {
      case 'stok':       return m.outOfStock > 0 ? `${m.outOfStock} bitti` : m.lowStock > 0 ? `${m.lowStock} az` : `${m.totalStock} adet`;
      case 'satis':      return m.todayCount > 0 ? `${m.todayCount} ┬╖ ${formatMoney(m.todayAmount)}` : 'Bug├╝n sat─▒┼ƒ yok';
      case 'siparis':    return m.pendingOrders > 0 ? `${m.pendingOrders} bekliyor` : 'Bekleyen yok';
      case 'malgiris':   return m.inTransit > 0 ? `${m.inTransit} yolda` : m.completedToday > 0 ? `${m.completedToday} teslim` : 'Yok';
      case 'kasa':       return formatMoney(m.totalKasa);
      case 'pos_ziraat': return formatMoney(m.posZ);
      case 'pos_is':     return formatMoney(m.posI);
      case 'pos_yk':     return formatMoney(m.posY);
      case 'ocek':       return m.ortakCekim > 0 ? formatMoney(m.ortakCekim) : 'Yok';
      case 'disborc':    return m.totalPayable > 0 ? formatMoney(m.totalPayable) : 'Yok';
      case 'otahsilat':  return m.ortakTahsilat > 0 ? formatMoney(m.ortakTahsilat) : 'Yok';
      case 'tahsilat':   return formatMoney(m.totalReceivable);
      case 'tedarikci':  return m.totalPayable > 0 ? `${formatMoney(m.totalPayable)} bor├º` : 'Bor├º yok';
    }
  }

  const errCount  = NODES.filter(n => getStatus(n.id) === 'err').length;
  const warnCount = NODES.filter(n => getStatus(n.id) === 'warn').length;
  const okCount   = NODES.filter(n => getStatus(n.id) === 'ok').length;

  const nodePos = Object.fromEntries(NODES.map(n => [n.id, n]));

  return (
    <div style={{ paddingBottom: 40 }}>
      {/* Ba┼ƒl─▒k */}
      <div style={{ display: 'flex', gap: 12, marginBottom: 20, flexWrap: 'wrap', alignItems: 'center' }}>
        <div style={{ flex: 1, minWidth: 160 }}>
          <h2 style={{ color: '#f1f5f9', fontWeight: 900, fontSize: '1.1rem', margin: 0 }}>ΓÜí Canl─▒ Muhasebe Kontrol Halkas─▒</h2>
          <p style={{ color: '#475569', fontSize: '0.78rem', margin: '4px 0 0' }}>T├╝m kanallar ger├ºek zamanl─▒ izleniyor</p>
        </div>
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
          {[
            { count: errCount,  color: '#ef4444', label: 'Kritik', icon: '≡ƒö┤' },
            { count: warnCount, color: '#f59e0b', label: 'Uyar─▒',  icon: '≡ƒƒí' },
            { count: okCount,   color: '#22c55e', label: 'Tamam',  icon: '≡ƒƒó' },
          ].map(b => (
            <div key={b.label} style={{ background: `${b.color}18`, border: `1px solid ${b.color}44`, borderRadius: 10, padding: '8px 16px', textAlign: 'center', minWidth: 64 }}>
              <div style={{ color: b.color, fontWeight: 900, fontSize: '1.3rem', lineHeight: 1 }}>{b.count}</div>
              <div style={{ color: `${b.color}cc`, fontSize: '0.68rem', fontWeight: 700, textTransform: 'uppercase', marginTop: 3, letterSpacing: '0.04em' }}>{b.icon} {b.label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Net Sermaye Band─▒ */}
      <div style={{
        background: m.netSermaye >= 0 ? 'rgba(34,197,94,0.06)' : 'rgba(239,68,68,0.06)',
        border: `1px solid ${m.netSermaye >= 0 ? 'rgba(34,197,94,0.25)' : 'rgba(239,68,68,0.25)'}`,
        borderRadius: 12, padding: '12px 20px', marginBottom: 20,
        display: 'flex', gap: 16, flexWrap: 'wrap', alignItems: 'center',
      }}>
        {[
          { label: 'Nakit',    value: m.nakit,    color: '#06b6d4' },
          { label: 'Banka',    value: m.banka,    color: '#6366f1' },
          { label: 'POS',      value: m.posZ + m.posI + m.posY, color: '#8b5cf6' },
          { label: 'Alacak',   value: m.totalReceivable, color: '#10b981' },
          { label: 'Bor├º',     value: -m.totalPayable,   color: '#ef4444' },
        ].map((item, idx, arr) => (
          <div key={item.label} style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <div style={{ textAlign: 'center' }}>
              <div style={{ color: '#475569', fontSize: '0.65rem', fontWeight: 600, textTransform: 'uppercase' }}>{item.label}</div>
              <div style={{ color: item.color, fontWeight: 700, fontSize: '0.92rem' }}>{item.value < 0 ? '-' : ''}{formatMoney(Math.abs(item.value))}</div>
            </div>
            {idx < arr.length - 1 && <span style={{ color: '#334155', fontWeight: 700 }}>{idx === arr.length - 2 ? 'ΓêÆ' : '+'}</span>}
          </div>
        ))}
        <span style={{ color: '#334155', fontWeight: 700, fontSize: '1.2rem' }}>=</span>
        <div style={{ background: m.netSermaye >= 0 ? 'rgba(34,197,94,0.12)' : 'rgba(239,68,68,0.12)', border: `1px solid ${m.netSermaye >= 0 ? 'rgba(34,197,94,0.35)' : 'rgba(239,68,68,0.35)'}`, borderRadius: 10, padding: '8px 18px', textAlign: 'center' }}>
          <div style={{ color: '#475569', fontSize: '0.65rem', fontWeight: 600, textTransform: 'uppercase' }}>Net Sermaye</div>
          <div style={{ color: m.netSermaye >= 0 ? '#22c55e' : '#ef4444', fontWeight: 900, fontSize: '1.15rem' }}>{formatMoney(m.netSermaye)}</div>
        </div>
      </div>

      {/* Halka */}
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      <div style={{ width: '100%', overflowX: 'auto', WebkitOverflowScrolling: 'touch' as any }}>
        <div style={{ position: 'relative', width: 780, height: 780, margin: '0 auto', flexShrink: 0 }}>
          {/* SVG ba─ƒlant─▒lar */}
          <svg style={{ position: 'absolute', inset: 0, width: 780, height: 780, pointerEvents: 'none' }}>
            {CONNECTIONS.map(([fromId, toId], i) => {
              const from = nodePos[fromId]; const to = nodePos[toId];
              if (!from || !to) return null;
              const x1 = from.x + 75; const y1 = from.y + 35;
              const x2 = to.x + 75;   const y2 = to.y + 35;
              const dx = x2 - x1; const dy = y2 - y1;
              const len = Math.sqrt(dx * dx + dy * dy);
              const ux = dx / len; const uy = dy / len;
              // Shorten line ends so they don't overlap nodes
              const sx = x1 + ux * 78; const sy = y1 + uy * 38;
              const ex = x2 - ux * 78; const ey = y2 - uy * 38;
              const mx = (sx + ex) / 2 - uy * 25;
              const my = (sy + ey) / 2 + ux * 25;
              const angle = Math.atan2(ey - my, ex - mx) * 180 / Math.PI;
              return (
                <g key={i}>
                  <path d={`M${sx},${sy} Q${mx},${my} ${ex},${ey}`} fill="none" stroke="rgba(100,116,139,0.22)" strokeWidth={1.5} strokeDasharray="5 4" />
                  <polygon points="-5,-4 0,5 5,-4"
                    fill="rgba(100,116,139,0.5)"
                    transform={`translate(${ex},${ey}) rotate(${angle + 90})`} />
                </g>
              );
            })}
          </svg>

          {/* Node'lar */}
          {NODES.map(node => {
            const st = getStatus(node.id);
            const c = S[st];
            return (
              <div key={node.id} style={{
                position: 'absolute', left: node.x, top: node.y,
                width: 150, height: 70, borderRadius: 40,
                background: c.bg, border: `2px solid ${c.border}`,
                boxShadow: `0 0 ${st === 'err' ? 20 : 12}px ${c.border}55, 0 4px 14px rgba(0,0,0,0.5)`,
                display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                padding: '0 12px',
                transition: 'all 0.4s ease',
                animation: st === 'err' ? 'halka-pulse 1.5s infinite' : st === 'warn' ? 'halka-warn 2s infinite' : undefined,
              }}>
                <div style={{ color: c.text, fontWeight: 800, fontSize: '0.62rem', letterSpacing: '0.05em', textTransform: 'uppercase', textAlign: 'center', lineHeight: 1.2 }}>{node.label}</div>
                <div style={{ color: `${c.text}bb`, fontSize: '0.6rem', marginTop: 3, maxWidth: 130, textAlign: 'center', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{getSub(node.id)}</div>
                <div style={{ position: 'absolute', top: 7, right: 11, width: 8, height: 8, borderRadius: '50%', background: c.dot, boxShadow: `0 0 6px ${c.dot}` }} />
              </div>
            );
          })}
        </div>
      </div>

      {/* ΓöÇΓöÇ Sistem Sa─ƒl─▒k Paneli ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      {healthReport && (
        <div style={{ marginTop: 28 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 14 }}>
            <h3 style={{ color: '#f1f5f9', fontWeight: 800, fontSize: '0.95rem', margin: 0 }}>≡ƒÅÑ Sistem Sa─ƒl─▒─ƒ─▒</h3>
            {/* Skor */}
            <div style={{
              padding: '4px 14px', borderRadius: 20,
              background: STATUS_COLORS[healthReport.overall].bg,
              border: `1px solid ${STATUS_COLORS[healthReport.overall].border}`,
              color: STATUS_COLORS[healthReport.overall].text,
              fontWeight: 800, fontSize: '0.85rem',
            }}>
              {healthReport.score}/100 ΓÇö {STATUS_COLORS[healthReport.overall].label}
            </div>
            <button
              onClick={recheck}
              disabled={fullChecking}
              style={{
                padding: '5px 14px', borderRadius: 8, border: '1px solid rgba(255,255,255,0.1)',
                background: 'rgba(255,255,255,0.05)', color: fullChecking ? '#334155' : '#94a3b8',
                cursor: fullChecking ? 'wait' : 'pointer', fontSize: '0.78rem', fontWeight: 600,
                transition: 'all 0.15s', marginLeft: 'auto',
              }}
              onMouseEnter={e => { if (!fullChecking) (e.currentTarget.style.background = 'rgba(255,255,255,0.1)'); }}
              onMouseLeave={e => { (e.currentTarget.style.background = 'rgba(255,255,255,0.05)'); }}
            >
              {fullChecking ? 'Γƒ│ Kontrol ediliyorΓÇª' : '≡ƒöä Yeniden Kontrol'}
            </button>
          </div>

          {/* Metrikler */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(210px, 1fr))', gap: 10 }}>
            {healthReport.metrics.map(metric => {
              const c = STATUS_COLORS[metric.status];
              return (
                <div key={metric.id} style={{
                  background: c.bg, border: `1px solid ${c.border}`,
                  borderRadius: 12, padding: '12px 14px',
                  transition: 'all 0.2s',
                }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 6 }}>
                    <span style={{ width: 8, height: 8, borderRadius: '50%', background: c.text, flexShrink: 0, boxShadow: `0 0 6px ${c.text}` }} />
                    <span style={{ color: '#94a3b8', fontSize: '0.72rem', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.06em' }}>{metric.name}</span>
                    <span style={{ marginLeft: 'auto', color: c.text, fontSize: '0.68rem', fontWeight: 700 }}>{c.label}</span>
                  </div>
                  <div style={{ color: c.text, fontSize: '1.1rem', fontWeight: 900, lineHeight: 1 }}>
                    {metric.value}{metric.unit ? <span style={{ fontSize: '0.72rem', fontWeight: 600, marginLeft: 2 }}>{metric.unit}</span> : ''}
                  </div>
                  {metric.detail && (
                    <div style={{ color: '#475569', fontSize: '0.68rem', marginTop: 4, lineHeight: 1.4 }}>{metric.detail}</div>
                  )}
                </div>
              );
            })}
          </div>

          {/* ├ûneriler */}
          {healthReport.recommendations.length > 0 && (
            <div style={{ marginTop: 14, background: 'rgba(245,158,11,0.06)', border: '1px solid rgba(245,158,11,0.2)', borderRadius: 12, padding: '12px 16px' }}>
              <div style={{ color: '#f59e0b', fontWeight: 700, fontSize: '0.78rem', marginBottom: 8, textTransform: 'uppercase', letterSpacing: '0.05em' }}>ΓÜá∩╕Å ├ûneriler</div>
              {healthReport.recommendations.map((rec, i) => (
                <div key={i} style={{ color: '#94a3b8', fontSize: '0.8rem', lineHeight: 1.5, display: 'flex', gap: 8, marginBottom: i < healthReport.recommendations.length - 1 ? 6 : 0 }}>
                  <span style={{ color: '#f59e0b', flexShrink: 0 }}>ΓÇ║</span>
                  {rec}
                </div>
              ))}
            </div>
          )}

          <div style={{ color: '#1e3a5f', fontSize: '0.62rem', marginTop: 8, textAlign: 'right' }}>
            Son kontrol: {new Date(healthReport.ts).toLocaleTimeString('tr-TR')}
            {healthReport.duration > 0 && ` ┬╖ ${healthReport.duration}ms`}
          </div>
        </div>
      )}

      <style>{`
        @keyframes halka-pulse {
          0%, 100% { box-shadow: 0 0 20px #ef444466, 0 4px 14px rgba(0,0,0,.5); }
          50%       { box-shadow: 0 0 36px #ef4444bb, 0 4px 20px rgba(0,0,0,.6); }
        }
        @keyframes halka-warn {
          0%, 100% { box-shadow: 0 0 12px #f59e0b44, 0 4px 14px rgba(0,0,0,.5); }
          50%       { box-shadow: 0 0 22px #f59e0b88, 0 4px 18px rgba(0,0,0,.6); }
        }
      `}</style>
    </div>
  );
}

import { useState } from 'react';
import { Modal } from '@/components/Modal';
import { useToast } from '@/components/Toast';
import { useConfirm } from '@/components/ConfirmDialog';
import { genId, formatMoney, calcProfit } from '@/lib/utils-tr';
import { exportArrayToExcel } from '@/lib/excelExport';
import type { DB, Product } from '@/types';

interface Props { db: DB; save: (fn: (prev: DB) => DB) => void; }

const empty: Omit<Product, 'id' | 'createdAt' | 'updatedAt'> = { name: '', category: 'soba', supplierId: '', brand: '', cost: 0, price: 0, stock: 0, minStock: 5, barcode: '', description: '' };

export default function Products({ db, save }: Props) {
  const { showToast } = useToast();
  const { showConfirm } = useConfirm();
  const [filter, setFilter] = useState('all');
  const [search, setSearch] = useState('');
  const [modalOpen, setModalOpen] = useState(false);
  const [form, setForm] = useState<Partial<Product>>(empty);
  const [editId, setEditId] = useState<string | null>(null);

  const productCats = db.productCategories || [];
  const getCategoryIcon = (id: string) => productCats.find(c => c.id === id)?.icon || '≡ƒôª';
  const getCategoryName = (id: string) => productCats.find(c => c.id === id)?.name || id;

  let products = db.products.filter(p => !p.deleted);
  if (filter === 'zero') products = products.filter(p => p.stock === 0);
  else if (filter === 'low') products = products.filter(p => p.stock > 0 && p.stock <= p.minStock);
  else if (filter !== 'all') products = products.filter(p => p.category === filter);
  if (search) products = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()) || (p.brand || '').toLowerCase().includes(search.toLowerCase()) || (p.barcode || '').includes(search));

  const openAdd = () => { const defCat = productCats[0]?.id || 'soba'; setForm({ ...empty, category: defCat }); setEditId(null); setModalOpen(true); };
  const openEdit = (p: Product) => { setForm({ ...p }); setEditId(p.id); setModalOpen(true); };

  const handleSave = () => {
    if (!form.name) { showToast('├£r├╝n ad─▒ gerekli!', 'error'); return; }
    const nowIso = new Date().toISOString();
    save(prev => {
      const products = [...prev.products];
      if (editId) {
        const i = products.findIndex(p => p.id === editId);
        if (i >= 0) products[i] = { ...products[i], ...form, updatedAt: nowIso } as Product;
        showToast('├£r├╝n g├╝ncellendi!', 'success');
      } else {
        const np: Product = { id: genId(), createdAt: nowIso, updatedAt: nowIso, name: '', category: productCats[0]?.id || 'soba', cost: 0, price: 0, stock: 0, minStock: 5, ...form } as Product;
        products.push(np);
        showToast('├£r├╝n eklendi!', 'success');
      }
      return { ...prev, products };
    });
    setModalOpen(false);
  };

  const handleDelete = (id: string) => {
    showConfirm('├£r├╝n├╝ Sil', 'Bu ├╝r├╝n├╝ silmek istedi─ƒinizden emin misiniz?', () => {
      const nowIso = new Date().toISOString();
      save(prev => ({ ...prev, products: prev.products.map(p => p.id === id ? { ...p, deleted: true, updatedAt: nowIso } : p) }));
      showToast('├£r├╝n silindi!', 'success');
    });
  };

  const f = (k: keyof Product, v: any) => setForm(prev => ({ ...prev, [k]: v }));

  const activeProducts = db.products.filter(p => !p.deleted);
  const totalValue = activeProducts.reduce((s, p) => s + p.cost * p.stock, 0);
  const outOfStock = activeProducts.filter(p => p.stock === 0).length;
  const lowStock = activeProducts.filter(p => p.stock > 0 && p.stock <= p.minStock).length;
  const siparisOnerisi = activeProducts.filter(p => p.stock <= p.minStock);

  return (
    <div>
      <div style={{ display: 'flex', gap: 12, alignItems: 'center', marginBottom: 20, flexWrap: 'wrap' }}>
        <button onClick={openAdd} style={{ background: '#ff5722', border: 'none', borderRadius: 10, color: '#fff', padding: '10px 20px', fontWeight: 700, cursor: 'pointer', fontSize: '0.9rem' }}>+ Yeni ├£r├╝n</button>
        <button onClick={() => { const rows = activeProducts.map(p => ({ Ad: p.name, Kategori: p.category, Marka: p.brand || '', 'Al─▒┼ƒ': p.cost, 'Sat─▒┼ƒ': p.price, Stok: p.stock, 'Min Stok': p.minStock, Barkod: p.barcode || '' })); exportArrayToExcel(rows, 'urun-listesi'); showToast('Excel indirildi!', 'success'); }} style={{ background: 'rgba(99,102,241,0.12)', border: '1px solid rgba(99,102,241,0.25)', borderRadius: 10, color: '#818cf8', padding: '10px 16px', fontWeight: 700, cursor: 'pointer', fontSize: '0.85rem' }}>≡ƒôè Excel</button>
        <input value={search} onChange={e => setSearch(e.target.value)} placeholder="≡ƒöì ├£r├╝n ara..." style={{ flex: 1, minWidth: 200, padding: '10px 14px', background: '#1e293b', border: '1px solid #334155', borderRadius: 10, color: '#f1f5f9', fontSize: '0.9rem' }} />
      </div>

      {siparisOnerisi.length > 0 && (
        <div style={{ background: 'rgba(245,158,11,0.08)', border: '1px solid rgba(245,158,11,0.25)', borderRadius: 12, padding: '12px 16px', marginBottom: 16, display: 'flex', alignItems: 'center', gap: 12, flexWrap: 'wrap' }}>
          <span style={{ fontSize: '1.2rem' }}>ΓÜá∩╕Å</span>
          <div style={{ flex: 1 }}>
            <span style={{ color: '#fcd34d', fontWeight: 700, fontSize: '0.88rem' }}>{siparisOnerisi.length} ├╝r├╝n sipari┼ƒ gerektirir: </span>
            <span style={{ color: '#94a3b8', fontSize: '0.82rem' }}>{siparisOnerisi.slice(0, 4).map(p => p.name).join(', ')}{siparisOnerisi.length > 4 ? ` +${siparisOnerisi.length - 4} daha` : ''}</span>
          </div>
          <button onClick={() => setFilter('low')} style={{ background: 'rgba(245,158,11,0.15)', border: '1px solid rgba(245,158,11,0.3)', borderRadius: 8, color: '#f59e0b', padding: '6px 14px', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 700, whiteSpace: 'nowrap' }}>Listele ΓåÆ</button>
        </div>
      )}

      <div style={{ display: 'flex', gap: 8, marginBottom: 20, flexWrap: 'wrap' }}>
        <Chip label="T├╝m├╝" active={filter === 'all'} onClick={() => setFilter('all')} />
        {productCats.map(c => <Chip key={c.id} label={`${c.icon} ${c.name}`} active={filter === c.id} onClick={() => setFilter(c.id)} />)}
        <Chip label="≡ƒö┤ Biten" active={filter === 'zero'} onClick={() => setFilter('zero')} danger={outOfStock > 0} count={outOfStock} />
        <Chip label="ΓÜá∩╕Å Az" active={filter === 'low'} onClick={() => setFilter('low')} warning={lowStock > 0} count={lowStock} />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(120px, 1fr))', gap: 12, marginBottom: 20 }}>
        {[
          { label: 'Toplam ├£r├╝n', value: String(db.products.length), color: '#3b82f6' },
          { label: 'Stok De─ƒeri', value: formatMoney(totalValue), color: '#10b981' },
          { label: 'Biten Stok', value: String(outOfStock), color: '#ef4444' },
          { label: 'Az Stok', value: String(lowStock), color: '#f59e0b' },
        ].map(s => (
          <div key={s.label} style={{ background: '#1e293b', borderRadius: 10, padding: '14px 16px', border: `1px solid ${s.color}22` }}>
            <div style={{ fontSize: '1.3rem', fontWeight: 800, color: s.color }}>{s.value}</div>
            <div style={{ color: '#64748b', fontSize: '0.78rem', marginTop: 2 }}>{s.label}</div>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: 14 }}>
        {products.length === 0 ? (
          <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: 48, color: '#64748b' }}>
            <div style={{ fontSize: '3rem', marginBottom: 12 }}>≡ƒôª</div>
            <p>├£r├╝n bulunamad─▒</p>
          </div>
        ) : products.map(p => {
          const margin = calcProfit(p.price, p.cost);
          const marginColor = margin >= 30 ? '#10b981' : margin >= 10 ? '#f59e0b' : '#ef4444';
          const stockStatus = p.stock === 0 ? { color: '#ef4444', label: '≡ƒö┤ Stok Yok' } : p.stock <= p.minStock ? { color: '#f59e0b', label: `ΓÜá∩╕Å Az: ${p.stock}` } : { color: '#10b981', label: `Γ£ô ${p.stock} adet` };
          return (
            <div key={p.id} style={{ background: '#1e293b', borderRadius: 12, border: `1px solid ${p.stock === 0 ? '#ef444433' : p.stock <= p.minStock ? '#f59e0b33' : '#334155'}`, padding: 16, transition: 'all 0.2s' }}
              onMouseEnter={e => (e.currentTarget as HTMLDivElement).style.transform = 'translateY(-2px)'}
              onMouseLeave={e => (e.currentTarget as HTMLDivElement).style.transform = ''}>
              <div style={{ fontSize: '2.2rem', marginBottom: 10, textAlign: 'center' }}>{getCategoryIcon(p.category)}</div>
              <h4 style={{ fontWeight: 700, marginBottom: 4, color: '#f1f5f9', fontSize: '0.95rem' }}>{p.name}</h4>
              <p style={{ color: '#64748b', fontSize: '0.8rem', marginBottom: 10 }}>{p.brand ? `${p.brand} ┬╖ ` : ''}{getCategoryName(p.category)}</p>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
                <span style={{ fontWeight: 700, color: '#f1f5f9', fontSize: '1rem' }}>{formatMoney(p.price)}</span>
                <span style={{ fontSize: '0.78rem', fontWeight: 700, color: marginColor }}>%{margin} markup</span>
              </div>
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
              {(p as any).costCurrency && (p as any).costCurrency !== 'TRY' && (
                <div style={{ fontSize: '0.72rem', color: '#64748b', marginBottom: 4 }}>
                  // eslint-disable-next-line @typescript-eslint/no-explicit-any
                  Al─▒┼ƒ: {p.cost} {(p as any).costCurrency}
                </div>
              )}
              <div style={{ color: stockStatus.color, fontSize: '0.85rem', fontWeight: 600, marginBottom: 10 }}>{stockStatus.label}</div>
              {p.barcode && <div style={{ fontSize: '0.72rem', color: '#475569', marginBottom: 10 }}>≡ƒöû {p.barcode}</div>}
              <div style={{ display: 'flex', gap: 8 }}>
                <button onClick={() => openEdit(p)} style={{ flex: 1, background: 'rgba(59,130,246,0.1)', border: '1px solid rgba(59,130,246,0.2)', borderRadius: 8, color: '#60a5fa', padding: '7px 0', cursor: 'pointer', fontWeight: 600, fontSize: '0.82rem' }}>Γ£Å∩╕Å D├╝zenle</button>
                <button onClick={() => handleDelete(p.id)} style={{ background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', borderRadius: 8, color: '#ef4444', padding: '7px 10px', cursor: 'pointer', fontWeight: 600 }}>≡ƒùæ∩╕Å</button>
              </div>
            </div>
          );
        })}
      </div>

      <Modal open={modalOpen} onClose={() => setModalOpen(false)} title={editId ? 'Γ£Å∩╕Å ├£r├╝n D├╝zenle' : 'Γ₧ò Yeni ├£r├╝n'}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14 }}>
          <div style={{ gridColumn: '1/-1' }}>
            <label style={lbl}>├£r├╝n Ad─▒ *</label>
            <input value={form.name || ''} onChange={e => f('name', e.target.value)} style={inp} placeholder="├£r├╝n ad─▒" />
          </div>
          <div>
            <label style={lbl}>Kategori</label>
            <select value={form.category || productCats[0]?.id || 'soba'} onChange={e => f('category', e.target.value)} style={inp}>
              {productCats.map(c => <option key={c.id} value={c.id}>{c.icon} {c.name}</option>)}
            </select>
          </div>
          <div>
            <label style={lbl}>Tedarik├ºi (opsiyonel)</label>
            <select value={form.supplierId || ''} onChange={e => f('supplierId', e.target.value)} style={inp}>
              <option value="">ΓÇö Se├ºilmedi ΓÇö</option>
              {db.suppliers.filter(s => !s.deleted).map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
          </div>
          <div>
            <label style={lbl}>Marka</label>
            <input value={form.brand || ''} onChange={e => f('brand', e.target.value)} style={inp} placeholder="Marka" />
          </div>
          <div>
            <label style={lbl}>Al─▒┼ƒ Fiyat─▒</label>
            <div style={{ display: 'flex', gap: 6 }}>
              <input type="number" inputMode="decimal" value={form.cost || 0} onChange={e => f('cost', parseFloat(e.target.value) || 0)} style={{ ...inp, flex: 1 }} min={0} step={0.01} />
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
              <select value={(form as any).costCurrency || 'TRY'} onChange={e => f('costCurrency', e.target.value)} style={{ ...inp, width: 70, flex: '0 0 70px' }}>
                <option value="TRY">Γé║</option>
                <option value="USD">$</option>
                <option value="EUR">Γé¼</option>
              </select>
            </div>
          </div>
          <div>
            <label style={lbl}>Sat─▒┼ƒ Fiyat─▒ (Γé║)</label>
            <input type="number" inputMode="decimal" value={form.price || 0} onChange={e => f('price', parseFloat(e.target.value) || 0)} style={inp} min={0} step={0.01} />
          </div>
          <div>
            <label style={lbl}>Stok</label>
            <input type="number" inputMode="decimal" value={form.stock || 0} onChange={e => f('stock', parseInt(e.target.value) || 0)} style={inp} min={0} />
          </div>
          <div>
            <label style={lbl}>Min. Stok</label>
            <input type="number" inputMode="decimal" value={form.minStock || 5} onChange={e => f('minStock', parseInt(e.target.value) || 0)} style={inp} min={0} />
          </div>
          <div>
            <label style={lbl}>Barkod</label>
            <input value={form.barcode || ''} onChange={e => f('barcode', e.target.value)} style={inp} placeholder="Barkod" />
          </div>
          <div style={{ gridColumn: '1/-1' }}>
            <label style={lbl}>A├º─▒klama</label>
            <textarea value={form.description || ''} onChange={e => f('description', e.target.value)} style={{ ...inp, minHeight: 60, resize: 'vertical' as const }} />
          </div>
          {form.cost && form.price ? (
            <div style={{ gridColumn: '1/-1', background: '#0f172a', borderRadius: 8, padding: '10px 14px', display: 'flex', gap: 20 }}>
              <span style={{ color: '#64748b', fontSize: '0.85rem' }}>Markup: <strong style={{ color: calcProfit(form.price, form.cost) >= 20 ? '#10b981' : '#f59e0b' }}>%{calcProfit(form.price, form.cost)}</strong></span>
              <span style={{ color: '#64748b', fontSize: '0.85rem' }}>K├ór: <strong style={{ color: '#10b981' }}>{formatMoney((form.price - form.cost) * (form.stock || 0))}</strong></span>
            </div>
          ) : null}
        </div>
        <div style={{ display: 'flex', gap: 10, marginTop: 20 }}>
          <button onClick={handleSave} style={{ flex: 1, background: '#10b981', border: 'none', borderRadius: 10, color: '#fff', padding: '11px 0', fontWeight: 700, cursor: 'pointer' }}>≡ƒÆ╛ Kaydet</button>
          <button onClick={() => setModalOpen(false)} style={{ background: '#273548', border: '1px solid #334155', borderRadius: 10, color: '#94a3b8', padding: '11px 20px', cursor: 'pointer' }}>─░ptal</button>
        </div>
      </Modal>
    </div>
  );
}

const lbl: React.CSSProperties = { display: 'block', marginBottom: 6, color: '#94a3b8', fontSize: '0.85rem', fontWeight: 500 };
const inp: React.CSSProperties = { width: '100%', padding: '10px 14px', background: 'rgba(15,23,42,0.6)', border: '1px solid #334155', borderRadius: 10, color: '#f1f5f9', fontSize: '0.9rem', boxSizing: 'border-box' };

function Chip({ label, active, onClick, danger, warning, count }: { label: string; active: boolean; onClick: () => void; danger?: boolean; warning?: boolean; count?: number }) {
  return (
    <button onClick={onClick} style={{ padding: '7px 14px', border: 'none', borderRadius: 10, cursor: 'pointer', fontWeight: 600, fontSize: '0.83rem', background: active ? '#ff5722' : danger ? 'rgba(239,68,68,0.1)' : warning ? 'rgba(245,158,11,0.1)' : '#273548', color: active ? '#fff' : danger ? '#ef4444' : warning ? '#f59e0b' : '#94a3b8', transition: 'all 0.2s', display: 'flex', alignItems: 'center', gap: 6 }}>
      {label} {count !== undefined && count > 0 && <span style={{ background: active ? 'rgba(255,255,255,0.2)' : danger ? '#ef4444' : '#f59e0b', color: '#fff', borderRadius: '50%', minWidth: 18, height: 18, display: 'inline-flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.72rem', fontWeight: 800 }}>{count}</span>}
    </button>
  );
}
